/**
 * theme.js
 * Enhanced theme and animation handling for modern portfolio
 * Uses GSAP and Lenis for smooth animations and interactions
 */

document.addEventListener('DOMContentLoaded', function () {
    // Theme toggle functionality
    const btn = document.getElementById('theme-toggle');
    if (btn) {
        btn.addEventListener('click', function () {
            const isLight = document.documentElement.getAttribute('data-theme') === 'light';
            if (isLight) {
                document.documentElement.removeAttribute('data-theme');
                try { localStorage.setItem('portfolio-theme', 'dark'); } catch (e) { /* ignore */ }
            } else {
                document.documentElement.setAttribute('data-theme', 'light');
                try { localStorage.setItem('portfolio-theme', 'light'); } catch (e) { /* ignore */ }
            }

            // Trigger UI refresh for animations
            document.documentElement.classList.add('theme-transition');
            setTimeout(() => {
                document.documentElement.classList.remove('theme-transition');
            }, 300);
        });
    }

    // Initialize GSAP animations
    initGSAPAnimations();

    // Initialize magnetic button effects
    initMagneticButtons();

    // Initialize floating elements
    initFloatingElements();

    // Initialize particle effects (subtle)
    initParticleEffects();

    // Initialize interactive elements
    initInteractiveElements();

    // Initialize animated counters
    initAnimatedCounters();

    // Initialize animated icons
    initAnimatedIcons();

    // Handle form submissions with enhanced feedback
    initFormEnhancements();

    // Initial animation trigger
    triggerInitialAnimations();

    // Site-wide UX features (run on every page)
    initScrollProgressBar();
    initBackToTop();
    initCopyEmailButtons();
    initHeroTypingEffect();
    initImageLightbox();
});

/**
 * Initialize GSAP-powered animations
 */
function initGSAPAnimations() {
    // GSAP is only loaded on index.html. On pages without it, skip silently
    // instead of throwing a ReferenceError that would halt every script
    // initialized after this call.
    if (typeof gsap === 'undefined') return;

    // Check if prefers-reduced-motion is enabled
    const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (reducedMotion) return;

    // Animate elements on scroll using GSAP ScrollTrigger
    gsap.utils.toArray('.animate-in').forEach((element) => {
        gsap.from(element, {
            opacity: 0,
            y: 40,
            duration: 0.8,
            ease: "power3.out",
            scrollTrigger: {
                trigger: element,
                start: "top 85%",
                end: "bottom 20%",
                toggleActions: "play none none reverse"
            }
        });
    });

    // Animate stat numbers
    gsap.utils.toArray('.stat-number').forEach((counter) => {
        // Prefer the data-target attribute (the real value to count up to).
        // Falls back to the element's own text for stat numbers that don't
        // use data-target at all.
        const raw = counter.hasAttribute('data-target') ? counter.getAttribute('data-target') : counter.innerText;
        const text = raw.trim();
        // Only animate if the content is a number
        if (!isNaN(text) && text !== '') {
            const target = parseInt(text);
            gsap.fromTo(counter,
                { innerText: 0 },
                {
                    innerText: target,
                    duration: 2.5,
                    ease: "power3.out",
                    snap: { innerText: 1 },
                    scrollTrigger: {
                        trigger: counter,
                        start: "top 80%"
                    },
                    onUpdate: function() {
                        counter.innerText = Math.round(this.targets()[0].innerText);
                    }
                }
            );
        }
    });

    // Animate achievement counts
    gsap.utils.toArray('.achievement-count').forEach((counter) => {
        const raw = counter.hasAttribute('data-target') ? counter.getAttribute('data-target') : counter.innerText;
        const text = raw.trim();
        // Only animate if the content is a number
        if (!isNaN(text) && text !== '') {
            const target = parseInt(text);
            gsap.fromTo(counter,
                { innerText: 0 },
                {
                    innerText: target,
                    duration: 2.5,
                    ease: "power3.out",
                    snap: { innerText: 1 },
                    scrollTrigger: {
                        trigger: counter,
                        start: "top 80%"
                    },
                    onUpdate: function() {
                        counter.innerText = Math.round(this.targets()[0].innerText);
                    }
                }
            );
        }
    });

    // Animate progress bars or skill bars if they exist
    gsap.utils.toArray('.progress-bar').forEach((bar) => {
        const width = bar.getAttribute('data-width') || '100%';
        gsap.fromTo(bar,
            { width: 0 },
            {
                width: width,
                duration: 2,
                ease: "power3.out",
                scrollTrigger: {
                    trigger: bar,
                    start: "top 80%"
                }
            }
        );
    });
}

/**
 * Initialize magnetic button effects
 */
function initMagneticButtons() {
    const magneticButtons = document.querySelectorAll('.magnetic');

    magneticButtons.forEach(button => {
        const bounds = {
            left: 0,
            top: 0,
            width: window.innerWidth,
            height: window.innerHeight
        };

        window.addEventListener('resize', () => {
            bounds.width = window.innerWidth;
            bounds.height = window.innerHeight;
        });

        button.addEventListener('mousemove', (e) => {
            const { left, top, width, height } = button.getBoundingClientRect();
            const x = e.clientX - left - width / 2;
            const y = e.clientY - top - height / 2;

            const distance = Math.sqrt(x * x + y * y);
            const maxDistance = Math.max(width, height) / 2;
            const strength = Math.min(1, distance / maxDistance);

            const moveX = (x * 0.15) * strength;
            const moveY = (y * 0.15) * strength;

            button.style.transform = `translate(${moveX}px, ${moveY}px) scale(1.03)`;
        });

        button.addEventListener('mouseleave', () => {
            button.style.transform = 'translate(0px, 0px) scale(1)';
            button.style.transition = 'transform 0.3s cubic-bezier(0.23, 1, 0.32, 1)';
        });

        button.addEventListener('mouseenter', () => {
            button.style.transition = 'none';
        });
    });
}

/**
 * Initialize floating elements
 */
function initFloatingElements() {
    const floatingElements = document.querySelectorAll('[data-float]');

    floatingElements.forEach((el, index) => {
        const speed = parseFloat(el.getAttribute('data-speed')) || 0.5;
        const intensity = parseFloat(el.getAttribute('data-intensity')) || 10;
        const delay = index * 0.1;

        let position = 0;
        let direction = 1;

        function float() {
            position += direction * speed;

            if (Math.abs(position) >= intensity) {
                direction *= -1;
            }

            el.style.transform = `translateY(${position}px)`;
            requestAnimationFrame(float);
        }

        // Start after delay
        setTimeout(() => {
            requestAnimationFrame(float);
        }, delay * 1000);
    });
}

/**
 * Initialize particle effects (subtle)
 */
function initParticleEffects() {
    // Create canvas for particles
    const existingCanvas = document.getElementById('particle-canvas');
    if (existingCanvas) return;

    const canvas = document.createElement('canvas');
    canvas.id = 'particle-canvas';
    canvas.style.position = 'fixed';
    canvas.style.top = '0';
    canvas.style.left = '0';
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    canvas.style.pointerEvents = 'none';
    canvas.style.zIndex = '-1';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    if (!ctx) return; // Environment doesn't support 2D canvas rendering — skip decorative effect
    let particles = [];
    let mouse = { x: 0, y: 0 };

    // Resize canvas
    function resizeCanvas() {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
        initParticles();
    }

    // Initialize particles
    function initParticles() {
        particles = [];
        const particleCount = Math.min(50, window.innerWidth / 20);

        for (let i = 0; i < particleCount; i++) {
            particles.push({
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height,
                radius: Math.random() * 2 + 1,
                color: `rgba(59, 130, 246, ${Math.random() * 0.3})`,
                speedX: (Math.random() - 0.5) * 0.5,
                speedY: (Math.random() - 0.5) * 0.5,
                originalY: Math.random() * canvas.height,
                delay: Math.random() * 100
            });
        }
    }

    // Update particles
    function updateParticles() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        particles.forEach(p => {
            // Update position
            p.x += p.speedX;
            p.y += p.speedY;

            // Add subtle wave motion
            p.y = p.originalY + Math.sin(Date.now() * 0.001 + p.delay) * 10;

            // Wrap around edges
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Draw particle
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
            ctx.fillStyle = p.color;
            ctx.fill();

            // Draw connection lines to nearby particles
            particles.forEach(p2 => {
                const dx = p.x - p2.x;
                const dy = p.y - p2.y;
                const distance = Math.sqrt(dx * dx + dy * dy);

                if (distance < 100) {
                    ctx.beginPath();
                    ctx.moveTo(p.x, p.y);
                    ctx.lineTo(p2.x, p2.y);
                    ctx.strokeStyle = `rgba(59, 130, 246, ${0.1 * (1 - distance / 100)})`;
                    ctx.lineWidth = 0.5;
                    ctx.stroke();
                }
            });
        });

        requestAnimationFrame(updateParticles);
    }

    // Mouse interaction
    window.addEventListener('mousemove', (e) => {
        mouse.x = e.clientX;
        mouse.y = e.clientY;
    });

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();
    requestAnimationFrame(updateParticles);
}

/**
 * Initialize interactive elements
 */
function initInteractiveElements() {
    // Card hover effects
    document.querySelectorAll('.card').forEach(card => {
        card.addEventListener('mousemove', (e) => {
            const rect = card.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            const centerX = rect.width / 2;
            const centerY = rect.height / 2;

            const rotateX = (y - centerY) / 20;
            const rotateY = (centerX - x) / 20;

            card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.03, 1.03, 1.03)`;
        });

        card.addEventListener('mouseleave', () => {
            card.style.transform = 'perspective(1000px) rotateX(0) rotateY(0) scale3d(1, 1, 1)';
            card.style.transition = 'transform 0.5s ease';
        });

        card.addEventListener('mouseenter', () => {
            card.style.transition = 'none';
        });
    });

    // Feature card 3D tilt
    document.querySelectorAll('.feature-card').forEach(card => {
        card.addEventListener('mousemove', (e) => {
            const rect = card.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            const centerX = rect.width / 2;
            const centerY = rect.height / 2;

            const rotateX = (y - centerY) / 15;
            const rotateY = (centerX - x) / 15;

            card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateY(-5px) scale(1.02)`;
        });

        card.addEventListener('mouseleave', () => {
            card.style.transform = 'perspective(1000px) rotateX(0) rotateY(0) translateY(0) scale(1)';
            card.style.transition = 'transform 0.5s ease';
        });

        card.addEventListener('mouseenter', () => {
            card.style.transition = 'none';
        });
    });
}

/**
 * Initialize animated counters
 */
function initAnimatedCounters() {
    if (typeof gsap === 'undefined') return;
    const counters = document.querySelectorAll('.animate-number');

    const options = {
        root: null,
        rootMargin: '0px',
        threshold: 0.1
    };

    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const counter = entry.target;
                const target = parseInt(counter.getAttribute('data-target') || counter.innerText);
                const duration = parseInt(counter.getAttribute('data-duration')) || 2000;
                const delay = parseInt(counter.getAttribute('data-delay')) || 0;

                // Reset counter
                counter.innerText = '0';

                // Animate counter
                gsap.fromTo(counter,
                    { innerText: 0 },
                    {
                        innerText: target,
                        duration: duration / 1000,
                        ease: "power3.out",
                        delay: delay / 1000,
                        snap: { innerText: 1 },
                        onUpdate: function() {
                            counter.innerText = Math.round(this.targets()[0].innerText);
                        }
                    }
                );

                // Unobserve after animation
                observer.unobserve(counter);
            }
        });
    }, options);

    counters.forEach(counter => {
        observer.observe(counter);
    });
}

/**
 * Initialize animated icons
 */
function initAnimatedIcons() {
    if (typeof gsap === 'undefined') return;
    // Animate feature icons on hover
    const featureIcons = document.querySelectorAll('.feature-icon svg');

    featureIcons.forEach(icon => {
        icon.addEventListener('mouseenter', () => {
            gsap.to(icon, {
                scale: 1.3,
                rotation: 10,
                duration: 0.4,
                ease: "power2.out"
            });

            // Pulse the parent circle
            const parentCircle = icon.closest('.feature-icon');
            if (parentCircle) {
                gsap.to(parentCircle, {
                    scale: 1.1,
                    duration: 0.4,
                    ease: "power2.out"
                });
            }
        });

        icon.addEventListener('mouseleave', () => {
            gsap.to(icon, {
                scale: 1,
                rotation: 0,
                duration: 0.3,
                ease: "power2.in"
            });

            // Reset the parent circle
            const parentCircle = icon.closest('.feature-icon');
            if (parentCircle) {
                gsap.to(parentCircle, {
                    scale: 1,
                    duration: 0.3,
                    ease: "power2.in"
                });
            }
        });
    });

    // Animate icons in buttons on hover
    const buttonIcons = document.querySelectorAll('.btn-icon svg');

    buttonIcons.forEach(icon => {
        icon.addEventListener('mouseenter', () => {
            gsap.to(icon, {
                scale: 1.2,
                rotation: 5,
                duration: 0.2,
                ease: "power2.out"
            });
        });

        icon.addEventListener('mouseleave', () => {
            gsap.to(icon, {
                scale: 1,
                rotation: 0,
                duration: 0.2,
                ease: "power2.in"
            });
        });
    });

    // Animate social icons in footer on hover
    const socialIcons = document.querySelectorAll('.footer-social a svg');

    socialIcons.forEach(icon => {
        icon.addEventListener('mouseenter', () => {
            gsap.to(icon, {
                scale: 1.2,
                rotation: 0,
                duration: 0.2,
                ease: "power2.out"
            });
        });

        icon.addEventListener('mouseleave', () => {
            gsap.to(icon, {
                scale: 1,
                rotation: 0,
                duration: 0.2,
                ease: "power2.in"
            });
        });
    });
}

/**
 * Handle form submissions with enhanced feedback
 */
function initFormEnhancements() {
    const forms = document.querySelectorAll('form');

    forms.forEach(form => {
        // Animated labels
        const inputs = form.querySelectorAll('input, textarea');
        inputs.forEach(input => {
            const wrapper = document.createElement('div');
            wrapper.className = 'input-group';
            input.parentNode.insertBefore(wrapper, input);
            wrapper.appendChild(input);

            if (input.previousElementSibling &&
                input.previousElementSibling.tagName === 'LABEL') {
                const label = input.previousElementSibling;
                label.classList.add('float-label');
                wrapper.insertBefore(label, input);
            }

            // Add focus effects
            input.addEventListener('focus', () => {
                wrapper.classList.add('focused');
            });

            input.addEventListener('blur', () => {
                if (!input.value) {
                    wrapper.classList.remove('focused');
                }
            });

            // Initialize state
            if (input.value) {
                wrapper.classList.add('focused');
            }
        });

        // Form submission feedback
        form.addEventListener('submit', (e) => {
            const submitBtn = form.querySelector('button[type="submit"], input[type="submit"]');
            if (submitBtn) {
                const originalText = submitBtn.innerHTML;
                submitBtn.disabled = true;
                submitBtn.innerHTML = `
                    <span>Submitting...</span>
                    <span class="loader"></span>
                `;

                // Simulate async operation (remove in production)
                setTimeout(() => {
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = '<span>Sent Successfully!</span>';
                    setTimeout(() => {
                        submitBtn.innerHTML = originalText;
                    }, 2000);
                }, 1500);
            }
        });
    });
}

/**
 * Trigger initial animations on page load
 */
function triggerInitialAnimations() {
    // Add slight delay to let browser paint first
    setTimeout(() => {
        // Animate elements that should appear immediately
        document.querySelectorAll('.hero, .section-header').forEach(el => {
            el.classList.add('animate-in');
        });

        // Trigger scroll events for elements already in view
        const elements = document.querySelectorAll('[data-animate]');
        elements.forEach(el => {
            const rect = el.getBoundingClientRect();
            if (rect.top <= window.innerHeight * 0.9 && rect.bottom >= 0) {
                el.classList.add('animate-in');
            }
        });
    }, 100);
}
/**
 * Fixed progress bar at the top of the viewport showing scroll position.
 * Works on every page since it's initialized globally.
 */
function initScrollProgressBar() {
    let bar = document.getElementById('scroll-progress-bar');
    if (!bar) {
        bar = document.createElement('div');
        bar.id = 'scroll-progress-bar';
        bar.setAttribute('aria-hidden', 'true');
        document.body.appendChild(bar);
    }

    let ticking = false;
    function updateBar() {
        const scrollTop = window.scrollY || document.documentElement.scrollTop;
        const docHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
        const pct = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
        bar.style.width = Math.min(100, Math.max(0, pct)) + '%';
        ticking = false;
    }

    window.addEventListener('scroll', function () {
        if (!ticking) {
            requestAnimationFrame(updateBar);
            ticking = true;
        }
    }, { passive: true });

    updateBar();
}

/**
 * Floating "back to top" button that appears after the user scrolls down.
 */
function initBackToTop() {
    let btn = document.getElementById('back-to-top');
    if (!btn) {
        btn = document.createElement('button');
        btn.id = 'back-to-top';
        btn.type = 'button';
        btn.setAttribute('aria-label', 'Back to top');
        btn.innerHTML = '<svg data-lucide="arrow-up"></svg>';
        document.body.appendChild(btn);
        safeCreateIcons();
    }

    window.addEventListener('scroll', function () {
        if (window.scrollY > 400) {
            btn.classList.add('visible');
        } else {
            btn.classList.remove('visible');
        }
    }, { passive: true });

    btn.addEventListener('click', function () {
        if (typeof lenis !== 'undefined' && lenis && typeof lenis.scrollTo === 'function') {
            lenis.scrollTo(0);
        } else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    });
}

/**
 * Adds "copy to clipboard" behavior to:
 *  1) any explicit button with class "copy-email-btn" (has data-email attr)
 *  2) every mailto: link site-wide, via an adjacent small icon button
 */
function initCopyEmailButtons() {
    async function copyText(text, btnEl) {
        try {
            await navigator.clipboard.writeText(text);
        } catch (e) {
            // Fallback for browsers without Clipboard API permissions
            const temp = document.createElement('textarea');
            temp.value = text;
            temp.style.position = 'fixed';
            temp.style.opacity = '0';
            document.body.appendChild(temp);
            temp.select();
            try { document.execCommand('copy'); } catch (e2) { /* ignore */ }
            document.body.removeChild(temp);
        }
        if (btnEl) {
            const original = btnEl.getAttribute('data-original-html') || btnEl.innerHTML;
            btnEl.setAttribute('data-original-html', original);
            btnEl.classList.add('copied');
            if (btnEl.classList.contains('copy-email-btn')) {
                btnEl.innerHTML = '<svg class="btn-icon" data-lucide="check"></svg> Copied!';
            }
            safeCreateIcons();
            setTimeout(function () {
                btnEl.classList.remove('copied');
                btnEl.innerHTML = original;
                safeCreateIcons();
            }, 2000);
        }
    }

    // Explicit "Copy Email" buttons
    document.querySelectorAll('.copy-email-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            copyText(btn.getAttribute('data-email') || 'jerwinenrique14@gmail.com', btn);
        });
    });

    // Small copy icon next to every mailto link site-wide (skip ones already inside a copy button)
    document.querySelectorAll('a[href^="mailto:"]').forEach(function (link) {
        if (link.closest('.copy-email-btn') || link.dataset.copyIconAdded) return;
        const email = link.getAttribute('href').replace('mailto:', '').split('?')[0];
        const iconBtn = document.createElement('button');
        iconBtn.type = 'button';
        iconBtn.className = 'copy-email-icon-btn';
        iconBtn.setAttribute('aria-label', 'Copy email address');
        iconBtn.innerHTML = '<svg data-lucide="copy"></svg>';
        iconBtn.addEventListener('click', function () {
            copyText(email, iconBtn);
        });
        link.insertAdjacentElement('afterend', iconBtn);
        link.dataset.copyIconAdded = 'true';
    });

    safeCreateIcons();
}

/**
 * Typewriter effect for the homepage hero title. No-ops on pages without
 * .hero-title, and respects prefers-reduced-motion.
 */
function initHeroTypingEffect() {
    const el = document.querySelector('.hero-title');
    if (!el) return;

    const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const fullText = el.textContent.trim();
    if (reducedMotion || !fullText) return;

    el.textContent = '';
    el.setAttribute('aria-label', fullText);

    const cursor = document.createElement('span');
    cursor.className = 'typing-cursor';
    cursor.style.height = '1em';

    let i = 0;
    const speed = 45;

    function type() {
        if (i <= fullText.length) {
            el.textContent = fullText.slice(0, i);
            el.appendChild(cursor);
            i++;
            setTimeout(type, speed);
        } else {
            setTimeout(function () { cursor.remove(); }, 1200);
        }
    }
    type();
}

/**
 * Lightweight image lightbox. Any <img> with class "lightbox-img" (or inside
 * a container with class "gallery") opens an enlarged view on click.
 */
function initImageLightbox() {
    const images = document.querySelectorAll('.lightbox-img, .gallery img');
    if (!images.length) return;

    let overlay = document.getElementById('image-lightbox-overlay');
    if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'image-lightbox-overlay';
        overlay.className = 'lightbox-overlay';
        overlay.innerHTML = '<button type="button" class="lightbox-close" aria-label="Close image"><svg data-lucide="x"></svg></button><img src="" alt="">';
        document.body.appendChild(overlay);
        safeCreateIcons();
    }

    const imgEl = overlay.querySelector('img');
    const closeBtn = overlay.querySelector('.lightbox-close');

    function close() {
        overlay.classList.remove('open');
        document.body.style.overflow = '';
    }

    images.forEach(function (img) {
        img.style.cursor = 'zoom-in';
        img.addEventListener('click', function () {
            imgEl.src = img.currentSrc || img.src;
            imgEl.alt = img.alt || '';
            overlay.classList.add('open');
            document.body.style.overflow = 'hidden';
        });
    });

    closeBtn.addEventListener('click', close);
    overlay.addEventListener('click', function (e) {
        if (e.target === overlay) close();
    });
    document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape') close();
    });
}
